                "# Oracle SQL Cookbook — Common Patterns\n\n## Pagination\n\n```sql\n-- 12c+ (preferred)\nSELECT * FROM employees ORDER BY last_name\nOFFSET :offset ROWS FETCH NEXT :page_size ROWS ONLY;\n\n-- Pre-12c\nSELECT * FROM (\n    SELECT t.*, ROWNUM rn FROM (\n        SELECT * FROM employees ORDER BY last_name\n    ) t WHERE ROWNUM <= :offset + :page_size\n) WHERE rn > :offset;\n```\n\n## Upsert (MERGE)\n\n```sql\n-- Single row upsert\nMERGE INTO config c\nUSING (SELECT :key AS k, :val AS v FROM DUAL) s\nON (c.config_key = s.k)\nWHEN MATCHED THEN UPDATE SET c.config_value = s.v, c.updated_at = SYSTIMESTAMP\nWHEN NOT MATCHED THEN INSERT (config_key, config_value, created_at)\n    VALUES (s.k, s.v, SYSTIMESTAMP);\n\n-- Batch upsert from staging table\nMERGE INTO target t USING staging s ON (t.id = s.id)\nWHEN MATCHED THEN UPDATE SET t.name = s.name, t.amount = s.amount\n    DELETE WHERE s.is_deleted = 1\nWHEN NOT MATCHED THEN INSERT (id, name, amount) VALUES (s.id, s.name, s.amount);\n```\n\n## Top-N per Group\n\n```sql\n-- Top 3 earners per department\nSELECT * FROM (\n    SELECT e.*, ROW_NUMBER() OVER (PARTITION BY department_id ORDER BY salary DESC) AS rn\n    FROM employees e WHERE is_active = 1\n) WHERE rn <= 3;\n```\n\n## Running Total\n\n```sql\nSELECT order_date, amount,\n    SUM(amount) OVER (ORDER BY order_date) AS running_total\nFROM daily_sales;\n```\n\n## Moving Average\n\n```sql\nSELECT order_date, amount,\n    AVG(amount) OVER (ORDER BY order_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS avg_7day\nFROM daily_sales;\n```\n\n## Gap Analysis (find missing IDs)\n\n```sql\nSELECT prev_id + 1 AS gap_start, id - 1 AS gap_end\nFROM (\n    SELECT id, LAG(id) OVER (ORDER BY id) AS prev_id FROM my_table\n) WHERE id - prev_id > 1;\n```\n\n## Pivot (Rows to Columns)\n\n```sql\n-- 11g+ PIVOT\nSELECT * FROM (\n    SELECT department_id, job_title, salary FROM employees\n)\nPIVOT (\n    AVG(salary) FOR job_title IN ('MANAGER' AS mgr, 'DEVELOPER' AS dev, 'ANALYST' AS anl)\n);\n```\n\n## Unpivot (Columns to Rows)\n\n```sql\nSELECT * FROM quarterly_sales\nUNPIVOT (\n    amount FOR quarter IN (q1_sales AS 'Q1', q2_sales AS 'Q2', q3_sales AS 'Q3', q4_sales AS 'Q4')\n);\n```\n\n## Hierarchical Query\n\n```sql\n-- Org chart\nSELECT LPAD(' ', (LEVEL-1)*2) || last_name AS name, LEVEL\nFROM employees\nSTART WITH manager_id IS NULL\nCONNECT BY PRIOR employee_id = manager_id\nORDER SIBLINGS BY last_name;\n\n-- Recursive CTE equivalent\nWITH RECURSIVE org AS (\n    SELECT employee_id, last_name, 1 AS lvl FROM employees WHERE manager_id IS NULL\n    UNION ALL\n    SELECT e.employee_id, e.last_name, o.lvl + 1 FROM employees e JOIN org o ON e.manager_id = o.employee_id\n)\nSELECT * FROM org ORDER BY lvl, last_name;\n```\n\n## Conditional Aggregation\n\n```sql\nSELECT\n    department_id,\n    COUNT(*) AS total,\n    COUNT(CASE WHEN is_active = 1 THEN 1 END) AS active,\n    COUNT(CASE WHEN is_active = 0 THEN 1 END) AS inactive,\n    SUM(CASE WHEN hire_date >= ADD_MONTHS(SYSDATE, -12) THEN 1 ELSE 0 END) AS hired_last_year\nFROM employees GROUP BY department_id;\n```\n\n## Duplicate Detection\n\n```sql\n-- Find duplicates\nSELECT email, COUNT(*) FROM employees GROUP BY email HAVING COUNT(*) > 1;\n\n-- Delete duplicates keeping the latest\nDELETE FROM employees WHERE ROWID NOT IN (\n    SELECT MAX(ROWID) FROM employees GROUP BY email\n);\n```\n\n## Date Range Generation\n\n```sql\n-- Generate all dates between two dates\nSELECT DATE '2024-01-01' + LEVEL - 1 AS dt\nFROM DUAL\nCONNECT BY LEVEL <= DATE '2024-12-31' - DATE '2024-01-01' + 1;\n```\n\n## Comma-Separated String to Rows\n\n```sql\n-- Split CSV string (pre-21c)\nSELECT TRIM(REGEXP_SUBSTR(:csv_string, '[^,]+', 1, LEVEL)) AS token\nFROM DUAL\nCONNECT BY LEVEL <= REGEXP_COUNT(:csv_string, ',') + 1;\n```\n\n## INSERT … RETURNING\n\n```sql\n-- PL/SQL (works in all versions)\nDECLARE v_id NUMBER;\nBEGIN\n    INSERT INTO employees (first_name, last_name, email, salary, department_id)\n    VALUES ('John', 'Doe', 'jdoe@x.com', 75000, 10)\n    RETURNING employee_id INTO v_id;\n    DBMS_OUTPUT.PUT_LINE('New ID: ' || v_id);\nEND;\n/\n```\n\n## WITH clause for Data-Driven Updates\n\n```sql\n-- Update based on complex calculation\nMERGE INTO employees e\nUSING (\n    WITH dept_avg AS (\n        SELECT department_id, AVG(salary) AS avg_sal FROM employees GROUP BY department_id\n    )\n    SELECT e2.employee_id, d.avg_sal * 1.1 AS new_salary\n    FROM employees e2 JOIN dept_avg d ON e2.department_id = d.department_id\n    WHERE e2.salary < d.avg_sal\n) src ON (e.employee_id = src.employee_id)\nWHEN MATCHED THEN UPDATE SET e.salary = src.new_salary;\n```\n\n## Check Table Existence\n\n```sql\n-- Pre-23c\nSELECT COUNT(*) FROM user_tables WHERE table_name = 'EMPLOYEES';\n\n-- 23c+\nCREATE TABLE IF NOT EXISTS employees (...);\nDROP TABLE IF EXISTS temp_staging;\n```\n\n## Grant All on Schema Objects\n\n```sql\n-- Pre-23c (must grant per object)\nBEGIN\n    FOR r IN (SELECT table_name FROM user_tables) LOOP\n        EXECUTE IMMEDIATE 'GRANT SELECT ON ' || r.table_name || ' TO reporting_user';\n    END LOOP;\nEND;\n/\n\n-- 23c+\nGRANT SELECT ANY TABLE ON SCHEMA hr TO reporting_user;\n```\n",
