            path: 'scripts/performance-analysis.sql',
            role: 'script',
            content:
                "-- ============================================================\n-- Oracle Performance Diagnostic Queries\n-- Use these to investigate slow queries and database issues.\n-- Requires SELECT on V$ views (DBA or SELECT_CATALOG_ROLE).\n-- ============================================================\n\n-- -------------------------------------------------------\n-- 1. TOP SQL BY ELAPSED TIME\n-- -------------------------------------------------------\nSELECT sql_id,\n       ROUND(elapsed_time / 1e6, 2) AS elapsed_sec,\n       executions,\n       ROUND(elapsed_time / NULLIF(executions, 0) / 1e6, 4) AS avg_sec,\n       buffer_gets,\n       ROUND(buffer_gets / NULLIF(executions, 0)) AS avg_gets,\n       rows_processed,\n       SUBSTR(sql_text, 1, 150) AS sql_preview\nFROM v$sql\nWHERE elapsed_time > 0\nORDER BY elapsed_time DESC\nFETCH FIRST 20 ROWS ONLY;\n\n-- -------------------------------------------------------\n-- 2. TOP SQL BY BUFFER GETS (logical I/O)\n-- -------------------------------------------------------\nSELECT sql_id,\n       buffer_gets,\n       executions,\n       ROUND(buffer_gets / NULLIF(executions, 0)) AS gets_per_exec,\n       ROUND(elapsed_time / 1e6, 2) AS elapsed_sec,\n       SUBSTR(sql_text, 1, 150) AS sql_preview\nFROM v$sql\nWHERE buffer_gets > 10000\nORDER BY buffer_gets DESC\nFETCH FIRST 20 ROWS ONLY;\n\n-- -------------------------------------------------------\n-- 3. CURRENTLY ACTIVE SQL\n-- -------------------------------------------------------\nSELECT s.sid, s.serial#, s.username, s.program,\n       s.sql_id, s.event, s.wait_class,\n       s.seconds_in_wait,\n       s.blocking_session,\n       SUBSTR(q.sql_text, 1, 200) AS sql_text\nFROM v$session s\nLEFT JOIN v$sql q ON s.sql_id = q.sql_id AND s.sql_child_number = q.child_number\nWHERE s.status = 'ACTIVE'\n  AND s.type = 'USER'\nORDER BY s.seconds_in_wait DESC;\n\n-- -------------------------------------------------------\n-- 4. BLOCKING SESSIONS (Lock Tree)\n-- -------------------------------------------------------\nSELECT\n    LPAD(' ', (LEVEL - 1) * 2) || s.sid AS sid,\n    s.serial#,\n    s.username,\n    s.event,\n    s.seconds_in_wait,\n    s.sql_id,\n    l.type AS lock_type,\n    DECODE(l.request, 0, 'Holder', 'Waiter') AS role\nFROM v$session s\nJOIN v$lock l ON s.sid = l.sid\nWHERE l.block > 0 OR l.request > 0\nSTART WITH l.block > 0 AND l.request = 0\nCONNECT BY PRIOR s.sid = s.blocking_session;\n\n-- -------------------------------------------------------\n-- 5. EXECUTION PLAN FOR A SQL_ID\n-- -------------------------------------------------------\n-- Replace :sql_id with the actual SQL ID\nSELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_CURSOR(:sql_id, NULL, 'ALLSTATS LAST'));\n\n-- -------------------------------------------------------\n-- 6. TABLE STATISTICS FRESHNESS\n-- -------------------------------------------------------\nSELECT table_name, num_rows, blocks, avg_row_len,\n       last_analyzed,\n       ROUND((SYSDATE - last_analyzed), 1) AS days_stale,\n       stale_stats\nFROM user_tab_statistics\nORDER BY last_analyzed NULLS FIRST;\n\n-- -------------------------------------------------------\n-- 7. INDEX STATISTICS & EFFICIENCY\n-- -------------------------------------------------------\nSELECT i.table_name, i.index_name, i.uniqueness,\n       i.leaf_blocks, i.distinct_keys, i.clustering_factor,\n       t.num_rows AS table_rows,\n       ROUND(i.clustering_factor / NULLIF(t.num_rows, 0) * 100, 1) AS clustering_pct,\n       -- If clustering_pct > 50%, index may not be efficient for range scans\n       i.last_analyzed\nFROM user_indexes i\nJOIN user_tables t ON i.table_name = t.table_name\nORDER BY i.table_name, i.index_name;\n\n-- -------------------------------------------------------\n-- 8. WAIT EVENTS SUMMARY\n-- -------------------------------------------------------\nSELECT wait_class, event, total_waits,\n       ROUND(time_waited / 100, 2) AS time_waited_sec,\n       ROUND(average_wait * 10, 2) AS avg_wait_ms\nFROM v$system_event\nWHERE wait_class NOT IN ('Idle', 'Other')\nORDER BY time_waited DESC\nFETCH FIRST 20 ROWS ONLY;\n\n-- -------------------------------------------------------\n-- 9. SGA / PGA MEMORY USAGE\n-- -------------------------------------------------------\nSELECT name, ROUND(value / 1024 / 1024, 2) AS mb\nFROM v$sga\nUNION ALL\nSELECT 'PGA Aggregate Target', ROUND(value / 1024 / 1024, 2)\nFROM v$parameter WHERE name = 'pga_aggregate_target';\n\n-- -------------------------------------------------------\n-- 10. SESSION-LEVEL I/O STATS\n-- -------------------------------------------------------\nSELECT s.sid, s.username, s.program,\n       si.physical_reads, si.block_gets, si.consistent_gets,\n       si.physical_reads + si.block_gets + si.consistent_gets AS total_io\nFROM v$session s\nJOIN v$sess_io si ON s.sid = si.sid\nWHERE s.type = 'USER' AND s.username IS NOT NULL\nORDER BY total_io DESC\nFETCH FIRST 20 ROWS ONLY;\n\n-- -------------------------------------------------------\n-- 11. FULL TABLE SCANS (from recent SQL)\n-- -------------------------------------------------------\nSELECT sql_id, plan_hash_value, operation, options,\n       object_name, cardinality, cost\nFROM v$sql_plan\nWHERE operation = 'TABLE ACCESS' AND options = 'FULL'\n  AND object_owner = UPPER(:schema_name)\nORDER BY cost DESC NULLS LAST\nFETCH FIRST 30 ROWS ONLY;\n\n-- -------------------------------------------------------\n-- 12. TEMP TABLESPACE USAGE\n-- -------------------------------------------------------\nSELECT s.sid, s.serial#, s.username, s.sql_id,\n       t.tablespace, t.blocks * 8192 / 1024 / 1024 AS used_mb\nFROM v$tempseg_usage t\nJOIN v$session s ON t.session_addr = s.saddr\nORDER BY t.blocks DESC;\n\n-- -------------------------------------------------------\n-- 13. UNDO USAGE\n-- -------------------------------------------------------\nSELECT s.sid, s.serial#, s.username, s.sql_id,\n       t.used_ublk * 8192 / 1024 / 1024 AS undo_mb,\n       t.start_time\nFROM v$transaction t\nJOIN v$session s ON t.addr = s.taddr\nORDER BY t.used_ublk DESC;\n\n-- -------------------------------------------------------\n-- 14. SQL PLAN HISTORY (is the plan changing?)\n-- -------------------------------------------------------\nSELECT sql_id, plan_hash_value,\n       TO_CHAR(timestamp, 'YYYY-MM-DD HH24:MI') AS first_seen,\n       executions, ROUND(elapsed_time / NULLIF(executions, 0) / 1e3, 2) AS avg_ms\nFROM v$sql\nWHERE sql_id = :sql_id\nORDER BY timestamp;\n\n-- -------------------------------------------------------\n-- 15. AWR TOP SQL (requires Diagnostics Pack license)\n-- -------------------------------------------------------\n\nSELECT * FROM dba_hist_sqlstat WHERE sql_id = :sql_id ORDER BY snap_id DESC;",
