            path: 'scripts/generate-schema-doc.sql',
            role: 'script',
            content:
                "-- ============================================================\n-- Generate Schema Documentation from Oracle Data Dictionary\n--\n-- Produces structured output that can be formatted into\n-- Markdown documentation. Replace :schema_name with target.\n-- ============================================================\n\n-- -------------------------------------------------------\n-- SECTION 1: Schema Overview\n-- -------------------------------------------------------\nSELECT 'SCHEMA OVERVIEW' AS section,\n       UPPER(:schema_name) AS schema_name,\n       (SELECT banner FROM v$version WHERE ROWNUM = 1) AS db_version\nFROM DUAL;\n\nSELECT object_type, COUNT(*) AS count\nFROM all_objects\nWHERE owner = UPPER(:schema_name) AND object_type NOT LIKE '%BODY'\nGROUP BY object_type\nORDER BY count DESC;\n\n-- -------------------------------------------------------\n-- SECTION 2: All Tables with Details\n-- -------------------------------------------------------\nSELECT 'TABLE: ' || t.table_name AS header,\n       t.num_rows,\n       t.last_analyzed,\n       t.partitioned,\n       NVL(c.comments, '(no comment)') AS table_comment,\n       ROUND(s.bytes / 1024 / 1024, 2) AS size_mb\nFROM all_tables t\nLEFT JOIN all_tab_comments c ON t.owner = c.owner AND t.table_name = c.table_name\nLEFT JOIN (\n    SELECT segment_name, SUM(bytes) bytes FROM dba_segments\n    WHERE owner = UPPER(:schema_name) AND segment_type LIKE 'TABLE%'\n    GROUP BY segment_name\n) s ON t.table_name = s.segment_name\nWHERE t.owner = UPPER(:schema_name)\nORDER BY t.table_name;\n\n-- -------------------------------------------------------\n-- SECTION 3: All Columns (grouped by table)\n-- -------------------------------------------------------\nSELECT tc.table_name,\n       tc.column_id,\n       tc.column_name,\n       CASE\n           WHEN tc.data_type = 'VARCHAR2' THEN 'VARCHAR2(' || tc.data_length || ')'\n           WHEN tc.data_type = 'NUMBER' AND tc.data_precision IS NOT NULL\n               THEN 'NUMBER(' || tc.data_precision || ',' || tc.data_scale || ')'\n           WHEN tc.data_type = 'NUMBER' THEN 'NUMBER'\n           WHEN tc.data_type IN ('CLOB','BLOB','DATE','TIMESTAMP(6)') THEN tc.data_type\n           ELSE tc.data_type || CASE WHEN tc.data_length IS NOT NULL AND tc.data_type LIKE '%CHAR%'\n               THEN '(' || tc.data_length || ')' ELSE '' END\n       END AS data_type_display,\n       DECODE(tc.nullable, 'N', 'NOT NULL', '') AS nullable,\n       tc.data_default AS default_value,\n       NVL(cc.comments, '') AS column_comment,\n       CASE WHEN pk.column_name IS NOT NULL THEN 'PK' ELSE '' END AS is_pk,\n       CASE WHEN fk.column_name IS NOT NULL THEN 'FK→' || fk.ref_table ELSE '' END AS is_fk\nFROM all_tab_columns tc\nLEFT JOIN all_col_comments cc ON tc.owner = cc.owner\n    AND tc.table_name = cc.table_name AND tc.column_name = cc.column_name\nLEFT JOIN (\n    SELECT cc2.table_name, cc2.column_name\n    FROM all_constraints c2 JOIN all_cons_columns cc2\n        ON c2.owner = cc2.owner AND c2.constraint_name = cc2.constraint_name\n    WHERE c2.owner = UPPER(:schema_name) AND c2.constraint_type = 'P'\n) pk ON tc.table_name = pk.table_name AND tc.column_name = pk.column_name\nLEFT JOIN (\n    SELECT cc3.table_name, cc3.column_name, rc.table_name AS ref_table\n    FROM all_constraints c3\n    JOIN all_cons_columns cc3 ON c3.owner = cc3.owner AND c3.constraint_name = cc3.constraint_name\n    JOIN all_constraints rc ON c3.r_owner = rc.owner AND c3.r_constraint_name = rc.constraint_name\n    WHERE c3.owner = UPPER(:schema_name) AND c3.constraint_type = 'R'\n) fk ON tc.table_name = fk.table_name AND tc.column_name = fk.column_name\nWHERE tc.owner = UPPER(:schema_name)\nORDER BY tc.table_name, tc.column_id;\n\n-- -------------------------------------------------------\n-- SECTION 4: All Foreign Key Relationships\n-- -------------------------------------------------------\nSELECT child.table_name || '.' ||\n       LISTAGG(cc.column_name, ',') WITHIN GROUP (ORDER BY cc.position)\n       || ' → ' ||\n       parent.table_name || '.' ||\n       LISTAGG(pc.column_name, ',') WITHIN GROUP (ORDER BY pc.position)\n       AS relationship,\n       child.constraint_name,\n       child.delete_rule\nFROM all_constraints child\nJOIN all_cons_columns cc ON child.owner = cc.owner AND child.constraint_name = cc.constraint_name\nJOIN all_constraints parent ON child.r_owner = parent.owner AND child.r_constraint_name = parent.constraint_name\nJOIN all_cons_columns pc ON parent.owner = pc.owner AND parent.constraint_name = pc.constraint_name\nWHERE child.owner = UPPER(:schema_name) AND child.constraint_type = 'R'\nGROUP BY child.table_name, parent.table_name, child.constraint_name, child.delete_rule\nORDER BY child.table_name;\n\n-- -------------------------------------------------------\n-- SECTION 5: All Indexes\n-- -------------------------------------------------------\nSELECT i.table_name, i.index_name, i.index_type, i.uniqueness, i.visibility,\n       LISTAGG(ic.column_name, ', ') WITHIN GROUP (ORDER BY ic.column_position) AS columns\nFROM all_indexes i\nJOIN all_ind_columns ic ON i.owner = ic.index_owner AND i.index_name = ic.index_name\nWHERE i.owner = UPPER(:schema_name)\nGROUP BY i.table_name, i.index_name, i.index_type, i.uniqueness, i.visibility\nORDER BY i.table_name, i.index_name;\n\n-- -------------------------------------------------------\n-- SECTION 6: Missing FK Indexes\n-- -------------------------------------------------------\nSELECT 'MISSING FK INDEX' AS issue,\n       c.table_name, cc.column_name, c.constraint_name\nFROM all_constraints c\nJOIN all_cons_columns cc ON c.owner = cc.owner AND c.constraint_name = cc.constraint_name\nWHERE c.owner = UPPER(:schema_name)\n  AND c.constraint_type = 'R'\n  AND NOT EXISTS (\n      SELECT 1 FROM all_ind_columns ic\n      WHERE ic.table_owner = c.owner AND ic.table_name = c.table_name\n        AND ic.column_name = cc.column_name AND ic.column_position = 1\n  );\n\n-- -------------------------------------------------------\n-- SECTION 7: PL/SQL Package Signatures\n-- -------------------------------------------------------\nSELECT a.package_name, a.object_name AS subprogram,\n       CASE WHEN a.position = 0 THEN 'FUNCTION' ELSE 'PROCEDURE' END AS type,\n       LISTAGG(\n           a.argument_name || ' ' || a.in_out || ' ' || a.data_type,\n           ', '\n       ) WITHIN GROUP (ORDER BY a.position) AS parameters\nFROM all_arguments a\nWHERE a.owner = UPPER(:schema_name)\n  AND a.package_name IS NOT NULL\n  AND a.data_level = 0\n  AND a.argument_name IS NOT NULL\nGROUP BY a.package_name, a.object_name, CASE WHEN a.position = 0 THEN 'FUNCTION' ELSE 'PROCEDURE' END\nORDER BY a.package_name, a.object_name;\n\n-- -------------------------------------------------------\n-- SECTION 8: Sequences\n-- -------------------------------------------------------\nSELECT sequence_name, min_value, increment_by, cache_size, last_number\nFROM all_sequences\nWHERE sequence_owner = UPPER(:schema_name)\nORDER BY sequence_name;",
