                '#!/usr/bin/env bash\n# run-sql.sh\n# Optional wrapper that runs a read-only Oracle investigation/diagnostic .sql file\n# through whichever Oracle client is available (SQLcl `sql`, or SQL*Plus `sqlplus`).\n#\n# This wrapper is for INVESTIGATION ONLY. It must never be used to run mutating\n# DDL/DML. If no client is found, it degrades gracefully and prints the queries\n# for the user to run manually.\n#\n# Usage:\n#   ./run-sql.sh <path-to.sql>\n#\n# Connection is taken from the environment so no credentials are ever hard-coded:\n#   ORACLE_CONNECT  e.g. user/password@//host:1521/SERVICE\n#                   (or a saved SQLcl/SQL*Plus connect identifier)\n#\n# Bind variables inside the .sql (e.g. :schema_name) are prompted for by the\n# client interactively, or can be supplied with a leading SQL*Plus DEFINE block.\n\nset -euo pipefail\n\nSQL_FILE="${1:-}"\n\nif [ -z "$SQL_FILE" ]; then\n    echo "Usage: $0 <path-to.sql>" >&2\n    exit 2\nfi\n\nif [ ! -f "$SQL_FILE" ]; then\n    echo "ERROR: SQL file not found: $SQL_FILE" >&2\n    exit 2\nfi\n\n# --- Refuse obviously mutating scripts (defense in depth) ---\nif grep -Eiq \'\\b(INSERT|UPDATE|DELETE|MERGE|DROP|TRUNCATE|ALTER|CREATE|GRANT|REVOKE)\\b\' "$SQL_FILE"; then\n    echo "REFUSING TO RUN: \'$SQL_FILE\' appears to contain mutating statements." >&2\n    echo "This wrapper only runs read-only investigation/diagnostic SQL." >&2\n    echo "Review the file and run it manually with your Oracle client if intended." >&2\n    exit 3\nfi\n\n# --- Detect an available client ---\nCLIENT=""\nif command -v sql >/dev/null 2>&1; then\n    CLIENT="sqlcl"\nelif command -v sqlplus >/dev/null 2>&1; then\n    CLIENT="sqlplus"\nfi\n\nif [ -z "$CLIENT" ]; then\n    echo "=============================================================="\n    echo "  No Oracle client found (neither SQLcl \'sql\' nor \'sqlplus\')."\n    echo "  Graceful fallback: here are the queries to run manually."\n    echo "=============================================================="\n    echo ""\n    cat "$SQL_FILE"\n    exit 0\nfi\n\nif [ -z "${ORACLE_CONNECT:-}" ]; then\n    echo "ERROR: ORACLE_CONNECT is not set." >&2\n    echo "Set it to a connect string, e.g.:" >&2\n    echo "  export ORACLE_CONNECT=\'user/password@//host:1521/SERVICE\'" >&2\n    echo "(Credentials are read from the environment and never stored.)" >&2\n    exit 2\nfi\n\necho "Running \'$SQL_FILE\' via $CLIENT (read-only)..."\n\ncase "$CLIENT" in\n    sqlcl)\n        sql -S "$ORACLE_CONNECT" @"$SQL_FILE"\n        ;;\n    sqlplus)\n        sqlplus -S "$ORACLE_CONNECT" @"$SQL_FILE"\n        ;;\nesac\n',
